module decoder_2to4_with_enable(
    input [1:0] control_input,
    input enable,
    output reg [3:0] data_out
);

always @(*) begin
    if (enable) begin
        data_out = 4'b0000;
        data_out[control_input] = 1'b1;
    end else begin
        data_out = 4'b0000;
    end
end

endmodule
